INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd3bae59b-0170-4071-8b4f-f96d6845ff42',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain + LlamaIndex — Using LlamaIndex Query Engines as Native LangChain Retrievers$escape$,
  $escape$LangChain and LlamaIndex solve different problems — LangChain orchestrates LLM workflows; LlamaIndex specializes in document indexing and structured retrieval. `langchain_community.retrievers.LlamaIndexRetriever` bridges them cleanly: you get LlamaIndex's indexing strategies as drop-in LangChain retrievers.

`SimpleDirectoryReader` handles multi-format ingestion (PDF, DOCX, HTML, Markdown) automatically. `VectorStoreIndex` defaults to in-memory storage but swaps to Pinecone or Weaviate via `StorageContext.from_defaults(vector_store=...)`. For hybrid retrieval, `RouterQueryEngine` dispatches queries across a `VectorStoreIndex` for semantic search and a `KeywordTableIndex` for exact-match lookups — choosing the right engine based on query intent.

Wrapping any LlamaIndex query engine with `LlamaIndexRetriever` makes it fully compatible with `RetrievalQA`, `ConversationalRetrievalChain`, or LCEL's pipe syntax. This lets you use `SummaryIndex` for condensed document answers and `VectorStoreIndex` for chunk-level retrieval — both within a single LangChain pipeline without duplicating embedding logic.

The practical split: delegate index architecture and retrieval granularity to LlamaIndex; keep prompt chaining, memory, and output parsing in LangChain.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, SimpleDirectoryReader
from llama_index.core.indices.keyword_table import KeywordTableIndex
from llama_index.core.query_engine import RouterQueryEngine
from llama_index.core.selectors import LLMSingleSelector
from langchain_community.retrievers import LlamaIndexRetriever
from langchain.chains import RetrievalQA
from langchain_groq import ChatGroq

docs = SimpleDirectoryReader("./docs").load_data()
vector_index = VectorStoreIndex.from_documents(docs)
keyword_index = KeywordTableIndex.from_documents(docs)

router_engine = RouterQueryEngine(
    selector=LLMSingleSelector.from_defaults(),
    query_engine_tools=[vector_index.as_query_engine(), keyword_index.as_query_engine()],
)

retriever = LlamaIndexRetriever(index=router_engine)
llm = ChatGroq(model="llama-3.3-70b-versatile")
chain = RetrievalQA.from_chain_type(llm=llm, retriever=retriever)
print(chain.invoke({"query": "What are the system requirements?"}))$escape$,
  $escape$python$escape$,
