INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '19a1fee0-5827-4707-80df-1317dcc72d58',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain + Ollama — Run Local LLMs Without Sending Data Anywhere$escape$,
  $escape$LangChain's `ChatOllama` and `OllamaEmbeddings` classes connect directly to a local Ollama server, letting you swap cloud models for on-device inference with a one-line change. Ollama serves models like Llama 3.2, Mistral, Gemma 2, and Phi-3 via a local REST API on `localhost:11434`. Because inference never leaves your machine, it's the go-to choice for RAG pipelines over sensitive codebases, private documents, or regulated data.

Swap `ChatOpenAI` for `ChatOllama` in any existing chain — the interface is identical. For embeddings in a local vector store, `OllamaEmbeddings` replaces `OpenAIEmbeddings` with zero changes to your retriever or `VectorstoreIndexCreator`. LangChain's streaming support also works out of the box via `stream()`, so you get token-by-token output locally. Pull a model once with `ollama pull llama3.2`, and your entire LangChain app runs fully offline. No API keys, no rate limits, no egress costs — just a running Ollama daemon.$escape$,
  $escape$from langchain_ollama import ChatOllama, OllamaEmbeddings
from langchain_community.vectorstores import FAISS
from langchain.chains import RetrievalQA

llm = ChatOllama(model="llama3.2", temperature=0)
embeddings = OllamaEmbeddings(model="nomic-embed-text")

vectorstore = FAISS.from_texts(
    ["All inference stays on-device.", "No API key required."],
    embedding=embeddings,
)

chain = RetrievalQA.from_chain_type(llm=llm, retriever=vectorstore.as_retriever())
print(chain.invoke({"query": "Where does inference run?"}))$escape$,
  $escape$python$escape$,
