INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7afe1e87-954c-4c76-881a-d6fbc600bed1',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain Embeddings — Choosing the Right Model and Measuring Semantic Similarity$escape$,
  $escape$LangChain's `Embeddings` interface abstracts over providers — OpenAI, Cohere, HuggingFace, and local models via Ollama — all exposing `embedDocuments()` and `embedQuery()`. The split matters: `embedQuery` applies query-specific instruction tuning on models like `text-embedding-3-large`, while `embedDocuments` batches efficiently.

For semantic similarity, avoid raw dot product unless embeddings are L2-normalized. LangChain's `MemoryVectorStore` uses cosine similarity by default, which is safer across models with different magnitude distributions.

Model comparison matters significantly. `text-embedding-3-small` (1536-dim) outperforms `text-embedding-ada-002` on MTEB benchmarks at lower cost. For local/offline use, `nomic-embed-text` via `OllamaEmbeddings` hits strong retrieval quality at 768 dims. Always match embedding model between indexing and query time — mixing models silently degrades recall without errors.

Use `embedQuery` for user queries, `embedDocuments` for your corpus. For RAG pipelines, pass your `Embeddings` instance directly into `SupabaseVectorStore` or `PGVector` — LangChain handles the insert and similarity search SQL under the hood.$escape$,
  $escape$import { OpenAIEmbeddings } from "@langchain/openai";
import { OllamaEmbeddings } from "@langchain/ollama";
import { MemoryVectorStore } from "langchain/vectorstores/memory";

// Swap models without changing downstream code
const embeddings = new OpenAIEmbeddings({ model: "text-embedding-3-small" });
// const embeddings = new OllamaEmbeddings({ model: "nomic-embed-text" });

const store = await MemoryVectorStore.fromTexts(
  ["LangChain supports pgvector", "Redis can cache embeddings", "FAISS runs locally"],
  [{ id: 1 }, { id: 2 }, { id: 3 }],
  embeddings
);

const results = await store.similaritySearchWithScore("vector database options", 2);
console.log(results); // [ [Document, 0.91], [Document, 0.87] ]$escape$,
  $escape$typescript$escape$,
