INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0008e7a1-8406-4392-807f-fae03f30b0d3',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain Agents — ReAct Loop with Custom Tools$escape$,
  $escape$LangChain's ReAct agent alternates between Thought → Action → Observation cycles until it reaches a final answer. Each cycle, the LLM reasons about which tool to invoke, the tool executes, and the result feeds back into context. Wire this up with `create_react_agent` from `langgraph` (the modern replacement for the deprecated `initialize_agent`). Define tools using the `@tool` decorator — LangChain auto-generates the JSON schema from the docstring and type hints, which the LLM uses for tool selection. Pass tools into `create_react_agent` alongside your model; the agent handles the loop internally via a compiled `StateGraph`. For multi-step tasks, the agent re-enters the reasoning node after each tool call until no more tool calls are emitted. Use `ToolNode` explicitly if you need to intercept tool execution — useful for adding retry logic, logging, or rate limiting. Set `recursion_limit` on your graph config to prevent runaway loops. Tool descriptions are your primary lever for selection accuracy; vague docstrings cause incorrect tool routing far more often than model capability issues.$escape$,
  $escape$from langchain_core.tools import tool
from langchain_openai import ChatOpenAI
from langgraph.prebuilt import create_react_agent

@tool
def get_repo_stars(repo: str) -> int:
    """Fetch the current GitHub star count for a given repo (owner/repo format)."""
    import httpx
    r = httpx.get(f"https://api.github.com/repos/{repo}")
    return r.json()["stargazers_count"]

llm = ChatOpenAI(model="gpt-4o", temperature=0)
agent = create_react_agent(llm, tools=[get_repo_stars])

result = agent.invoke({"messages": [("user", "How many stars does langchain-ai/langchain have?")]})
print(result["messages"][-1].content)$escape$,
  $escape$python$escape$,
