INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '93877c9b-fecc-4ddf-a0a1-2c81f07db052',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain Cost Management — Token Counting, Caching, and Smart Model Routing$escape$,
  $escape$LangChain exposes token usage directly via `AIMessage.usage_metadata` and `get_num_tokens()` on any chat model. Use `model.get_num_tokens_from_messages(messages)` before invoking to estimate cost and gate expensive calls. For caching, drop in `InMemoryCache` or `RedisSemanticCache` — semantic caching matches semantically similar prompts so identical-intent queries hit the cache even with different phrasing. Enable globally with `set_llm_cache(RedisSemanticCache(redis_url=..., embedding=embeddings))`. For batching, pass a list of inputs to `chain.batch([input1, input2], config={"max_concurrency": 5})` — this parallelizes requests while respecting rate limits. Model routing is cleanest with a `RunnableBranch` or a custom `RunnableLambda` that inspects token count: route short, simple prompts to `gpt-4o-mini` and reserve `gpt-4o` for long-context or complex reasoning tasks. Combine with `with_fallbacks()` to automatically downgrade on quota errors. Track spend per chain run using `LangSmith` callbacks, which log token usage per trace automatically.$escape$,
  $escape$from langchain.globals import set_llm_cache
from langchain_community.cache import RedisSemanticCache
from langchain_openai import ChatOpenAI, OpenAIEmbeddings
from langchain_core.runnables import RunnableLambda, RunnablePassthrough

set_llm_cache(RedisSemanticCache(redis_url="redis://localhost:6379", embedding=OpenAIEmbeddings()))

mini = ChatOpenAI(model="gpt-4o-mini")
full = ChatOpenAI(model="gpt-4o")

def route_by_tokens(input: dict):
    tokens = mini.get_num_tokens(input["question"])
    return full if tokens > 300 else mini

router = RunnableLambda(route_by_tokens)
chain = RunnablePassthrough.assign(model=router) | (lambda x: x["model"].invoke(x["question"]))

results = chain.batch([{"question": q} for q in questions], config={"max_concurrency": 4})$escape$,
  $escape$python$escape$,
