INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dc757b94-a88a-45c0-9f68-2a55167c71ca',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain Evaluation — LLM-as-Judge, RAGAS, and Benchmarks That Actually Catch Regressions$escape$,
  $escape$LangChain's `langchain.evaluation` module ships three evaluator families for production RAG pipelines. `load_evaluator("labeled_criteria")` wires any ChatModel as a judge against reference answers — pass `criteria="correctness"` for factual scoring or define custom rubrics via `EvaluatorType.LABELED_SCORE_STRING`. For RAG-specific signal, RAGAS integrates via `RagasEvaluatorChain`, which wraps `faithfulness`, `answer_relevancy`, and `context_precision` into LangChain-compatible callables — scoring retrieval and generation independently.

The real leverage comes from pairing both with LangSmith's `evaluate()` runner. Supply a `Dataset` of question/context/ground_truth triples plus a list of evaluators; LangSmith runs your chain, collects full traces, and aggregates scores into a single experiment view. Use `context_recall` to isolate retriever failures from generator failures before they reach users.

For regression tracking, `langchain_benchmarks` ships task suites like `ToolUsage` and `RetrievalTask` with pre-scored reference runs — no custom harness needed. Stack all three layers: RAGAS for component-level RAG metrics, LLM-as-judge for holistic output quality, and `langchain_benchmarks` for capability regression across model upgrades.$escape$,
  $escape$from langchain.evaluation import load_evaluator, EvaluatorType
from langsmith.evaluation import evaluate, LangChainStringEvaluator
from ragas.metrics import faithfulness, context_precision
from ragas.langchain import RagasEvaluatorChain

# LLM-as-judge: correctness scored against ground truth
criteria_eval = LangChainStringEvaluator(
    "labeled_criteria",
    config={"criteria": "correctness"},
)

# RAGAS faithfulness wrapped as a LangChain evaluator
ragas_faithfulness = RagasEvaluatorChain(metric=faithfulness)

results = evaluate(
    "your-langsmith-dataset",
    llm_or_chain_factory=your_rag_chain,
    evaluators=[criteria_eval],
    verbose=True,
)
print(results.aggregate_feedback)$escape$,
  $escape$python$escape$,
