INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '92515ae3-309f-43c6-a31f-3c59a2334305',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain Safety & Guardrails — Injection Prevention, Schema Enforcement, and Moderation$escape$,
  $escape$LangChain exposes three composable guardrail layers. First, prompt injection: keep user input strictly inside `HumanMessage` via `ChatPromptTemplate.from_messages()`. Never f-string user data into a `SystemMessage` — doing so lets adversaries overwrite your system constraints at runtime. Second, hallucination mitigation via `with_structured_output()`: binding a Pydantic model forces the LLM to emit structured JSON and lets you attach `@field_validator` rules (e.g., requiring `sources` to be non-empty). When the LLM violates the schema, LangChain automatically retries with the validation error appended. For persistent failures, `RetryOutputParser.from_llm()` re-prompts with the original parse error as context. Third, output filtering: `OpenAIModerationChain` wraps any LCEL chain and raises `ValueError` on policy violations before output surfaces to your app — drop it at the end of the pipe. Stack these as: isolation → schema enforcement → moderation. Each layer is independently composable via the `|` operator, so you can add or remove layers without restructuring the chain.$escape$,
  $escape$from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain.chains import OpenAIModerationChain
from pydantic import BaseModel, field_validator

class CitedAnswer(BaseModel):
    text: str
    sources: list[str]  # enforced citation reduces hallucination
    @field_validator("sources")
    def must_cite(cls, v):
        if not v: raise ValueError("Cite at least one source")
        return v

llm = ChatOpenAI(model="gpt-4o")
# User input isolated in HumanMessage — blocks system-prompt injection
prompt = ChatPromptTemplate.from_messages([
    ("system", "Answer Python questions only. Refuse all else."),
    ("human", "{question}"),
])
chain = prompt | llm.with_structured_output(CitedAnswer)
moderated_chain = chain | OpenAIModerationChain(llm=ChatOpenAI())$escape$,
  $escape$python$escape$,
